import matplotlib.pyplot as plt

def load_csv(filename):
    with open(filename, 'r') as f:
        lines = f.readlines()

    headers = lines[0].strip().split(",")
    data = {h: [] for h in headers}

    for line in lines[1:]:
        cols = line.strip().split(",")
        for i, col in enumerate(cols):
            data[headers[i]].append(float(col))

    return data


def main():
    # The three CSV files generated by your Java code
    files = {
        "QuickSort Worst Case": "QuickSortWorst.csv",
        "QuickSort Average Case": "QuickSortAverage.csv",
        "QuickSort Best Case": "QuickSortBest.csv",
        "MergeSort Worst Case": "MergeSortWorst.csv",
        "MergeSort Average Case": "MergeSortAverage.csv",
        "MergeSort Best Case": "MergeSortBest.csv",
    }

    plt.figure(figsize=(10,6))

    for label, filename in files.items():
        data = load_csv(filename)
        plt.plot(
            data["N"],
            data["Time(ns)"],
            marker='o',
            label=label,
        )

    plt.xlabel("N (input size)")
    plt.ylabel("Average Time (ns)")
    plt.yscale('log')
    plt.title("MergeSort vs QuickSort")

    plt.legend()
    plt.grid(True)

    plt.savefig("MergeSort v QuickSort Comparison.png", dpi = 150)
    plt.show()
    plt.close()


if __name__ == "__main__":
    main()